import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const ProfilePage = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [activeTab, setActiveTab] = useState('products');
  const [myProducts, setMyProducts] = useState([]);

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem('userInfo'));
    if (userInfo) {
      setUser(userInfo);
      // 👇 Gọi hàm lấy tin của tôi
      fetchMyProducts(userInfo._id);
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const fetchMyProducts = async (userId) => {
    try {
        const { data } = await axios.get(`http://localhost:5000/api/products/user/${userId}`);
        setMyProducts(data);
    } catch (error) { console.error("Lỗi lấy tin:", error); }
  };

  const handleLogout = () => {
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  if (!user) return null;

  return (
    <div className="container py-4">
      <header className="d-flex align-items-center mb-4 pb-3 border-bottom">
        <h2 className="fw-bold text-chotot m-0" style={{ cursor: 'pointer' }} onClick={() => navigate('/')}>HaiHand</h2>
        <span className="ms-3 text-muted border-start ps-3">Trang Quản Lý</span>
      </header>

      <div className="row">
        <div className="col-md-3 mb-4">
          <div className="card border-0 shadow-sm">
            <div className="card-body text-center border-bottom">
              <div className="rounded-circle bg-warning d-flex align-items-center justify-content-center mx-auto mb-2" style={{width: '60px', height: '60px', fontSize: '24px'}}>{user.name.charAt(0).toUpperCase()}</div>
              <h5 className="mb-0">{user.name}</h5>
            </div>
            <div className="list-group list-group-flush">
              <button className={`list-group-item list-group-item-action ${activeTab === 'products' ? 'fw-bold bg-light' : ''}`} onClick={() => setActiveTab('products')}>📋 Tin đăng của tôi</button>
              <button className="list-group-item list-group-item-action text-danger" onClick={handleLogout}>🚪 Đăng xuất</button>
            </div>
          </div>
        </div>

        <div className="col-md-9">
          <div className="card border-0 shadow-sm h-100">
            <div className="card-body">
              <h4 className="fw-bold mb-4">Tin đăng của tôi ({myProducts.length})</h4>
              
              {myProducts.length === 0 ? (
                  <div className="text-center text-muted py-5">
                      <p>Bạn chưa đăng tin nào cả.</p>
                      <button className="btn btn-warning" onClick={() => navigate('/post-product')}>Đăng tin ngay</button>
                  </div>
              ) : (
                  myProducts.map(prod => (
                    <div key={prod._id} className="d-flex justify-content-between align-items-center border-bottom py-3">
                      <div className="d-flex align-items-center">
                          <img src={prod.image} alt="" style={{width: '60px', height: '60px', objectFit: 'cover', borderRadius: '8px', marginRight: '15px'}} />
                          <div>
                              <h6 className="mb-1">{prod.name}</h6>
                              <span className="text-danger fw-bold">{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(prod.price)}</span>
                              <br/><small className="text-muted">Ngày đăng: {new Date(prod.createdAt).toLocaleDateString('vi-VN')}</small>
                          </div>
                      </div>
                      <div><span className="badge bg-success">Đang hiển thị</span></div>
                    </div>
                  ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;
